       const interval = setInterval(() => { if (active) load(); }, 10 * 1000);
       ```

   - **src/app/api/vessels/[id]/route.ts**
     - Created new PATCH endpoint (47 lines) to enable vessel editing
     - Full implementation:
       ```typescript
       export async function PATCH(req: Request, ctx: { params: Promise<{ id: string }> }) {
         const user = await getCurrentUser();
         if (!user) return NextResponse.json({ error: "Unauthenticated" }, { status: 401 });

         const { id } = await ctx.params;

         const vessel = await db.vessel.findUnique({ where: { id }, select: { userId: true } });
         if (!vessel) return NextResponse.json({ error: "Vessel not found" }, { status: 404 });
         if (vessel.userId !== user.id && user.role !== "ADMIN") {
           return NextResponse.json({ error: "Forbidden" }, { status: 403 });
         }

         const body = await req.json().catch(() => null) as {
           boatName?: string;
           boatNumber?: string;
           boatType?: string;
           yardNumber?: string;
         } | null;

         if (!body) return NextResponse.json({ error: "Invalid body" }, { status: 400 });

         const data: Record<string, string | null> = {};
         if (body.boatName !== undefined) data.boatName = String(body.boatName).trim();
         if (body.boatNumber !== undefined) data.boatNumber = String(body.boatNumber).trim();
         if (body.boatType !== undefined) data.boatType = body.boatType ? String(body.boatType).trim() : null;
         if (body.yardNumber !== undefined) data.yardNumber = body.yardNumber ? String(body.yardNumber).trim() : null;

         if (data.boatName !== undefined && !data.boatName) {
           return NextResponse.json({ error: "Boat name cannot be empty" }, { status: 400 });
         }

         try {
           const updated = await db.vessel.update({ where: { id }, data });
           return NextResponse.json(updated);
         } catch (err) {
           if (err instanceof Prisma.PrismaClientKnownRequestError && err.code === "P2025") {
             return NextResponse.json({ error: "Vessel not found" }, { status: 404 });
           }
           return NextResponse.json({ error: "Update failed" }, { status: 500 });
         }
       }
       ```
     - Validates boat name is not empty, allows partial updates, owner or admin authorization

   - **src/app/dashboard/dashboard-client.tsx**
     - Customer dashboard with vessel management
