       {editingVesselId === v.id ? (
         <form onSubmit={(e) => saveEditVessel(e, v.id)} className="mt-3 space-y-2 rounded-xl border border-sky-100 bg-sky-50 p-3">
           <p className="text-[10px] font-semibold uppercase tracking-wider text-sky-600">Edit vessel details</p>
           <div className="grid grid-cols-2 gap-2">
             {/* 4 input fields for boatName, boatNumber, boatType, yardNumber */}
           </div>
           <div className="flex gap-2 pt-0.5">
             <Button type="submit" size="sm" disabled={editVesselPending}>
               {editVesselPending ? "Saving…" : "Save"}
             </Button>
             <Button type="button" size="sm" variant="ghost" onClick={() => setEditingVesselId(null)}>Cancel</Button>
           </div>
         </form>
       ) : null}
       ```

   - **src/components/conditions-widget.tsx**
     - Weather/marine conditions widget
     - Added Pwllheli hardcoded location:
       ```typescript
       const PWLLHELI = { lat: 52.9263, lon: -4.4138, timezone: "Europe/London", name: "Pwllheli" };
       ```
     - Simplified ConditionsWidget to single panel:
       ```typescript
       export function ConditionsWidget() {
         const [data, setData] = useState<Conditions | null>(null);
         const [loading, setLoading] = useState(true);
         const [time, setTime] = useState("");

         useEffect(() => {
           const fetch_ = async () => {
             try {
               const res = await fetch(
                 `/api/conditions?lat=${PWLLHELI.lat}&lon=${PWLLHELI.lon}&timezone=${encodeURIComponent(PWLLHELI.timezone)}`
               );
               setData(await res.json());
             } finally {
               setLoading(false);
             }
           };
           fetch_();
         }, []);

         useEffect(() => {
           const tick = () => setTime(localTime(PWLLHELI.timezone));
           tick();
           const id = setInterval(tick, 1000);
           return () => clearInterval(id);
         }, []);

         return (
           <ConditionsPanel
             title="Destination Conditions"
             location={PWLLHELI.name}
             time={time}
             data={data}
             loading={loading}
             accent="teal"
           />
         );
       }
       ```
     - Removed geolocation logic, destination search UI, and forecast selectors
     - Moved old multi-location widget code to _UnusedDestWidget() function for potential future use

